namespace sv_9b55c8e27b7b4c7689715d89e7051dbe.Services;

public class AppointmentService
{
    private static readonly List<string> Doctors =
    [
        "Dr. Smith",
        "Dr. Johnson",
        "Dr. Patel",
        "Dr. Williams"
    ];

    private static readonly Dictionary<string, List<string>> DoctorTimeSlots = new()
    {
        ["Dr. Smith"] = ["9:00 AM", "10:00 AM", "11:00 AM", "2:00 PM", "3:00 PM"],
        ["Dr. Johnson"] = ["8:00 AM", "10:00 AM", "1:00 PM", "4:00 PM"],
        ["Dr. Patel"] = ["9:30 AM", "10:00 AM", "11:30 AM", "2:30 PM"],
        ["Dr. Williams"] = ["8:30 AM", "10:00 AM", "12:00 PM", "3:30 PM"]
    };

    // Doctors that do NOT accept self-pay
    private static readonly HashSet<string> NoSelfPayDoctors = ["Dr. Smith"];

    // Emails with outstanding balances
    private static readonly HashSet<string> OutstandingBalanceEmails =
        ["taken@example.com"];

    // Time slots that are "already taken" (simulates race condition)
    private static readonly HashSet<string> TakenSlots = ["10:00 AM"];

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>(Doctors));
    }

    public Task<List<string>> GetAvailableSlotsAsync(string doctor, DateOnly date)
    {
        if (DoctorTimeSlots.TryGetValue(doctor, out var slots))
        {
            return Task.FromResult(new List<string>(slots));
        }

        return Task.FromResult(new List<string>());
    }

    /// <summary>
    /// Validates patient/appointment data against server-side business rules.
    /// Returns a dictionary of field name → error message for any failures.
    /// An empty dictionary means validation passed.
    /// </summary>
    public Task<Dictionary<string, string>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, string>();

        if (OutstandingBalanceEmails.Contains(email))
        {
            errors[nameof(AppointmentModel.Email)] = "Account has outstanding balance";
        }

        if (insuranceProvider == "None" && NoSelfPayDoctors.Contains(doctor))
        {
            errors[nameof(AppointmentModel.Doctor)] =
                "Selected doctor does not accept self-pay patients";
        }

        if (TakenSlots.Contains(timeSlot))
        {
            errors[nameof(AppointmentModel.TimeSlot)] = "This slot is no longer available";
        }

        return Task.FromResult(errors);
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_9b55c8e27b7b4c7689715d89e7051dbe.Services;

public class AppointmentModel
{
    // Step 1 fields
    [Required(ErrorMessage = "Patient name is required.")]
    public string PatientName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Please enter a valid email address.")]
    public string Email { get; set; } = string.Empty;

    [Required(ErrorMessage = "Phone number is required.")]
    public string Phone { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select an insurance provider.")]
    public string InsuranceProvider { get; set; } = string.Empty;

    // Step 2 fields
    [Required(ErrorMessage = "Please select a doctor.")]
    public string Doctor { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a date.")]
    public DateOnly? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Please select a time slot.")]
    public string TimeSlot { get; set; } = string.Empty;

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason cannot exceed 500 characters.")]
    public string ReasonForVisit { get; set; } = string.Empty;

    // Custom validation for future date
    public string? ValidateDate()
    {
        if (AppointmentDate.HasValue && AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
        {
            return "Appointment date must be in the future.";
        }

        return null;
    }
}

