@page "/book-appointment"
@using sv_9b55c8e27b7b4c7689715d89e7051dbe.Services
@rendermode InteractiveServer
@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h3 class="mb-4">Book an Appointment</h3>

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="bookAppointment">
    <DataAnnotationsValidator />

    @* ── STEP 1 ── *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label class="form-label" for="patientName">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="Model.PatientName" />
            <ValidationMessage For="() => Model.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="email">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
            @if (serverErrors.TryGetValue(nameof(Model.Email), out var emailErr))
            {
                <div class="validation-message">@emailErr</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="phone">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="insurance">Insurance Provider</label>
            <InputSelect id="insurance" class="form-select" @bind-Value="Model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => Model.InsuranceProvider" />
        </div>
    </fieldset>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
            Next
        </button>
    }

    @* ── STEP 2 ── *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label" for="doctor">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-select"
                             @bind-Value="Model.Doctor"
                             @bind-Value:after="OnDoctorOrDateChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.Doctor" />
                @if (serverErrors.TryGetValue(nameof(Model.Doctor), out var docErr))
                {
                    <div class="validation-message">@docErr</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="date">Date</label>
                <InputDate id="date" class="form-control"
                           @bind-Value="Model.AppointmentDate"
                           @bind-Value:after="OnDoctorOrDateChanged" />
                <ValidationMessage For="() => Model.AppointmentDate" />
                @if (dateError is not null)
                {
                    <div class="validation-message">@dateError</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="timeslot">Time Slot</label>
                <InputSelect id="timeslot" class="form-select" @bind-Value="Model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.TimeSlot" />
                @if (serverErrors.TryGetValue(nameof(Model.TimeSlot), out var slotErr))
                {
                    <div class="validation-message">@slotErr</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="reason">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" rows="3"
                               @bind-Value="Model.ReasonForVisit" />
                <ValidationMessage For="() => Model.ReasonForVisit" />
            </div>

            <button type="button" class="btn btn-outline-secondary me-2" @onclick="BackToStep1">
                Back
            </button>
            <button type="button" class="btn btn-info me-2" @onclick="CheckAvailability"
                    disabled="@isChecking">
                @(isChecking ? "Checking…" : "Check Availability")
            </button>
            <button type="submit" class="btn btn-success" disabled="@(!availabilityChecked)">
                Confirm Appointment
            </button>
        </fieldset>
    }
</EditForm>

@if (submitted)
{
    <div class="alert alert-success mt-4" role="alert">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentModel Model { get; set; } = new();

    private bool showStep2;
    private bool isChecking;
    private bool availabilityChecked;
    private bool submitted;
    private string? dateError;

    private List<string> doctors = [];
    private List<string> availableSlots = [];
    private Dictionary<string, string> serverErrors = new();

    private EditContext? editContext;

    protected override void OnInitialized()
    {
        editContext = new EditContext(Model);
    }

    private void ProceedToStep2()
    {
        // Validate only step-1 fields
        editContext = new EditContext(Model);
        var isValid = true;
        var messageStore = new ValidationMessageStore(editContext);

        if (string.IsNullOrWhiteSpace(Model.PatientName))
        {
            messageStore.Add(() => Model.PatientName, "Patient name is required.");
            isValid = false;
        }

        if (string.IsNullOrWhiteSpace(Model.Email))
        {
            messageStore.Add(() => Model.Email, "Email is required.");
            isValid = false;
        }
        else if (!new System.ComponentModel.DataAnnotations.EmailAddressAttribute().IsValid(Model.Email))
        {
            messageStore.Add(() => Model.Email, "Please enter a valid email address.");
            isValid = false;
        }

        if (string.IsNullOrWhiteSpace(Model.Phone))
        {
            messageStore.Add(() => Model.Phone, "Phone number is required.");
            isValid = false;
        }

        if (string.IsNullOrWhiteSpace(Model.InsuranceProvider))
        {
            messageStore.Add(() => Model.InsuranceProvider, "Please select an insurance provider.");
            isValid = false;
        }

        editContext.NotifyValidationStateChanged();

        if (!isValid)
        {
            return;
        }

        showStep2 = true;
        LoadDoctorsAsync();
    }

    private async void LoadDoctorsAsync()
    {
        doctors = await AppointmentSvc.GetDoctorsAsync();
        StateHasChanged();
    }

    private async Task OnDoctorOrDateChanged()
    {
        // Reset availability when doctor or date changes
        availabilityChecked = false;
        serverErrors.Clear();
        dateError = null;
        Model.TimeSlot = string.Empty;

        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            dateError = Model.ValidateDate();
            if (dateError is null)
            {
                availableSlots = await AppointmentSvc.GetAvailableSlotsAsync(
                    Model.Doctor, Model.AppointmentDate.Value);
            }
            else
            {
                availableSlots = [];
            }
        }
        else
        {
            availableSlots = [];
        }
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();
        dateError = Model.ValidateDate();

        // Validate step 2 fields locally first
        var hasLocalError = false;

        if (string.IsNullOrWhiteSpace(Model.Doctor))
        {
            serverErrors[nameof(Model.Doctor)] = "Please select a doctor.";
            hasLocalError = true;
        }

        if (!Model.AppointmentDate.HasValue)
        {
            dateError = "Please select a date.";
            hasLocalError = true;
        }
        else if (dateError is not null)
        {
            hasLocalError = true;
        }

        if (string.IsNullOrWhiteSpace(Model.TimeSlot))
        {
            serverErrors[nameof(Model.TimeSlot)] = "Please select a time slot.";
            hasLocalError = true;
        }

        if (string.IsNullOrWhiteSpace(Model.ReasonForVisit))
        {
            serverErrors[nameof(Model.ReasonForVisit)] = "Reason for visit is required.";
            hasLocalError = true;
        }
        else if (Model.ReasonForVisit.Length > 500)
        {
            serverErrors[nameof(Model.ReasonForVisit)] = "Reason cannot exceed 500 characters.";
            hasLocalError = true;
        }

        if (hasLocalError)
        {
            return;
        }

        isChecking = true;

        var result = await AppointmentSvc.ValidatePatientAsync(
            Model.Email,
            Model.InsuranceProvider,
            Model.Doctor,
            Model.TimeSlot);

        isChecking = false;

        if (result.Count > 0)
        {
            serverErrors = result;
            availabilityChecked = false;
        }
        else
        {
            availabilityChecked = true;
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
        availabilityChecked = false;
        serverErrors.Clear();
        dateError = null;
    }

    private void HandleSubmit()
    {
        submitted = true;
    }
}

