+            messageStore.Add(() => Model.PatientName, "Patient name is required.");
+            isValid = false;
+        }
+
+        if (string.IsNullOrWhiteSpace(Model.Email))
+        {
+            messageStore.Add(() => Model.Email, "Email is required.");
+            isValid = false;
+        }
+        else if (!new System.ComponentModel.DataAnnotations.EmailAddressAttribute().IsValid(Model.Email))
+        {
+            messageStore.Add(() => Model.Email, "Please enter a valid email address.");
+            isValid = false;
+        }
+
+        if (string.IsNullOrWhiteSpace(Model.Phone))
+        {
+            messageStore.Add(() => Model.Phone, "Phone number is required.");
+            isValid = false;
+        }
+
+        if (string.IsNullOrWhiteSpace(Model.InsuranceProvider))
+        {
+            messageStore.Add(() => Model.InsuranceProvider, "Please select an insurance provider.");
+            isValid = false;
+        }
+
+        editContext.NotifyValidationStateChanged();
+
+        if (!isValid)
+        {
+            return;
+        }
+
+        showStep2 = true;
+        LoadDoctorsAsync();
+    }
+
+    private async void LoadDoctorsAsync()
+    {
+        doctors = await AppointmentSvc.GetDoctorsAsync();
+        StateHasChanged();
+    }
+
+    private async Task OnDoctorOrDateChanged()
+    {
+        // Reset availability when doctor or date changes
+        availabilityChecked = false;
+        serverErrors.Clear();
+        dateError = null;
+        Model.TimeSlot = string.Empty;
+
+        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
+        {
+            dateError = Model.ValidateDate();
+            if (dateError is null)
+            {
+                availableSlots = await AppointmentSvc.GetAvailableSlotsAsync(
