+            }
+            else
+            {
+                availableSlots = [];
+            }
+        }
+        else
+        {
+            availableSlots = [];
+        }
+    }
+
+    private async Task CheckAvailability()
+    {
+        serverErrors.Clear();
+        dateError = Model.ValidateDate();
+
+        // Validate step 2 fields locally first
+        var hasLocalError = false;
+
+        if (string.IsNullOrWhiteSpace(Model.Doctor))
+        {
+            serverErrors[nameof(Model.Doctor)] = "Please select a doctor.";
+            hasLocalError = true;
+        }
+
+        if (!Model.AppointmentDate.HasValue)
+        {
+            dateError = "Please select a date.";
+            hasLocalError = true;
+        }
+        else if (dateError is not null)
+        {
+            hasLocalError = true;
+        }
+
+        if (string.IsNullOrWhiteSpace(Model.TimeSlot))
+        {
+            serverErrors[nameof(Model.TimeSlot)] = "Please select a time slot.";
+            hasLocalError = true;
+        }
+
+        if (string.IsNullOrWhiteSpace(Model.ReasonForVisit))
+        {
+            serverErrors[nameof(Model.ReasonForVisit)] = "Reason for visit is required.";
+            hasLocalError = true;
+        }
+        else if (Model.ReasonForVisit.Length > 500)
+        {
+            serverErrors[nameof(Model.ReasonForVisit)] = "Reason cannot exceed 500 characters.";
+            hasLocalError = true;
+        }
+
+        if (hasLocalError)
+        {
+            return;
+        }
+
+        isChecking = true;
+
+        var result = await AppointmentSvc.ValidatePatientAsync(
+            Model.Email,
+            Model.InsuranceProvider,
+            Model.Doctor,
+            Model.TimeSlot);
+
+        isChecking = false;
+
+        if (result.Count > 0)
+        {
+            serverErrors = result;
+            availabilityChecked = false;
+        }
+        else
+        {
+            availabilityChecked = true;
+        }
+    }
+
+    private void BackToStep1()
+    {
+        showStep2 = false;
+        availabilityChecked = false;
+        serverErrors.Clear();
+        dateError = null;
+    }
+
+    private void HandleSubmit()
+    {
+        submitted = true;
+    }
+}
